const data = $input.item.json;
const book = data.book;
const author = data.author || '';
const sp = data.system_prompt || '';
const up = data.user_prompt || '';

if (book) {
  return [{
    json: {
      book: book,
      author: author,
      system_prompt: sp,
      user_prompt: up || '请以书籍拆解专家的身份，用中文拆解《' + book + '》。作者：' + (author || '未知') + '。请严格按照 System Prompt 中定义的 JSON 格式输出中文结果。'
    }
  }];
}
return [{json: {book: null, author: null, error: 'No book'}}];

var { execSync } = require('child_process');
var dir = '/Users/a123/Documents/Obsidian Vault/拆书';
var payload = JSON.stringify({book_title: $json.book_title, tags: $json.tags, category: $json.category, next_suggestions: $json.next_suggestions});
try {
  var out = execSync('cd "' + dir + '" && node scripts/recommendation-engine.js update \'' + payload.replace(/'/g, "'\\''") + '\'', {encoding:'utf-8', maxBuffer: 10485760});
  return [{json: {success: true, output: out}}];
} catch(e) { return [{json: {success: false, error: e.message}}]; }

